이제 하단에 skills 컴포넌트를 만든 후 about 페이지에 컴포넌트를 임포트 합니다.

```javascript title="src/app/about/page.js"
import AboutCoverSection from "@/src/components/About/AboutCoverSection";
import Skills from "@/src/components/About/Skills";

const About = () => {
  return (
    <>
      <AboutCoverSection />
      <Skills />
      <h2 className="mt-8 font-semibold text-2xl self-start mx-20 text-dark ">
        Do you have a project idea? Contact me, and together we can turn that
        dream into reality.
      </h2>
    </>
  );
};

export default About;
```

```javascript title="src/components/About/Skills.js"
const SkillList = [
  "next.js",
  "tailwind css",
  "javaScript",
  "solidity",
  "truffle",
  "hardhat",
  "firebase",
  "supabase",
  "generative AI",
];

const Skills = () => {
  return (
    <section className="w-full flex flex-col p-20 border-b-2 border-dark text-dark">
      <span className="font-semibold text-4xl text-accent">
        I'm proficient in...
      </span>
      <ul className="flex flex-wrap mt-8">
        {SkillList.map((item, index) => {
          return (
            <li
              key={index}
              className="font-semibold inline-block capitalize text-2xl py-5 px-12 border-2 border-dark rounded mr-6 mb-6 hover:scale-105 transition-all ease duration-200 cursor-pointer"
            >
              {item}
            </li>
          );
        })}
      </ul>
    </section>
  );
};

export default Skills;
```

